class Solution:
    def largestLocal(self, grid):
        n = len(grid)
        res = []
        for i in range(n - 2):
            row = []
            for j in range(n - 2):
                m = grid[i][j]
                for di in range(3):
                    for dj in range(3):
                        if grid[i + di][j + dj] > m:
                            m = grid[i + di][j + dj]
                row.append(m)
            res.append(row)
        return res

