class Solution:
    def largestLocal(self, grid):
        n = len(grid)
        res = [[0] * (n - 2) for _ in range(n - 2)]
        for i in range(n - 2):
            for j in range(n - 2):
                best = 0
                for r in range(i, i + 3):
                    rowmax = max(grid[r][j:j + 3])
                    if rowmax > best:
                        best = rowmax
                res[i][j] = best
        return res

