var largestLocal = function(grid) {
    const n = grid.length;
    const res = [];
    for (let i = 0; i < n - 2; i++) {
        const row = [];
        for (let j = 0; j < n - 2; j++) {
            let best = 0;
            for (let r = i; r < i + 3; r++)
                for (let c = j; c < j + 3; c++)
                    if (grid[r][c] > best) best = grid[r][c];
            row.push(best);
        }
        res.push(row);
    }
    return res;
};
